code = """import json
# Load previous tool results from storage
meta = var_call_w3rRjZz9OeKpLhuB1vC8PpsV
articles_path = var_call_y3uVUfkbkg4ckAAsgerqWwDY
# articles_path is a filepath to the JSON result
with open(articles_path, 'r') as f:
    articles = json.load(f)

# Build a mapping from article_id to combined text (title + description)
art_map = {str(a.get('article_id')): ((a.get('title') or '') + ' ' + (a.get('description') or '')).lower() for a in articles}

total = len(meta)

# Keyword sets for classification
business_kw = ['company', 'profit', 'profits', 'revenue', 'stocks', 'market', 'earnings', 'trade', 'wheat', 'export', 'import', 'settled', 'lawsuit', 'settlement', 'bank', 'econom', 'oil', 'producer prices', 'settles', 'price', 'sales', 'settlement', 'settled', 'settlement']
scitech_kw = ['science', 'technology', 'nasa', 'space', 'probe', 'shuttle', 'intel', 'microsoft', 'phone', 'mobile', 'e-mail', 'email', 'laboratory', 'research', 'physics', 'nuclear', 'genesis', 'gyro-gen', 'gameboy', 'micro-games', 'computer', 'software', 'hardware', 'server', 'storage']
sports_kw = ['pro bowl', 'olymp', 'quarter', 'match', 'goal', 'tournament', 'u.s. open', 'champions league', 'coach', 'score', 'win', 'defeat', 'season', 'semi-final', 'quarter-final', 'red sox', 'giants', 'dodgers', 'capriati', 'serena', 'ruud', 'manchester united', 'cycling', 'sprint', 'sprinter']

def classify(text):
    if not text:
        return 'World'
    # Business first (to catch revenue/stock stories about tech companies)
    for kw in business_kw:
        if kw in text:
            return 'Business'
    for kw in scitech_kw:
        if kw in text:
            return 'Science/Technology'
    for kw in sports_kw:
        if kw in text:
            return 'Sports'
    return 'World'

counts = {'Science/Technology':0,'Business':0,'Sports':0,'World':0}
for row in meta:
    aid = str(row.get('article_id'))
    text = art_map.get(aid, '')
    cat = classify(text)
    counts[cat] += 1

scitech_count = counts['Science/Technology']
fraction = scitech_count / total if total > 0 else None

result = {
    'total_articles': total,
    'scitech_count': scitech_count,
    'fraction_decimal': round(fraction, 6) if fraction is not None else None,
    'fraction_percent': round(fraction * 100, 4) if fraction is not None else None,
    'breakdown': counts
}

print("__RESULT__:")
print(json.dumps(result))"""

